// src/pages/LoginForm.js
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { loginUser } from "../services/api";

// Simple email/password login that stores JWT and redirects to /dashboard. [15]
export default function LoginForm() {
  const navigate = useNavigate(); // programmatic navigation after success. [17]
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const onSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSubmitting(true);
    try {
      const data = await loginUser({ email: email.trim(), password });
      // Token is saved in loginUser; navigate to dashboard after success. [15]
      if (data?.token || localStorage.getItem("nfxtoken")) {
        navigate("/dashboard", { replace: true });
      } else {
        setError("Login succeeded, but no token returned");
      }
    } catch (err) {
      if (err?.response?.status === 401) setError("Invalid credentials");
      else setError("Login failed");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div style={{ display: "grid", placeItems: "center", minHeight: "80vh" }}>
      <form onSubmit={onSubmit} style={{ width: 340, display: "grid", gap: 12 }}>
        <h2 style={{ margin: 0 }}>Sign in</h2>

        {error && <div style={{ color: "red" }}>{error}</div>}

        <label style={{ display: "grid", gap: 6 }}>
          <span>Email</span>
          <input
            type="email"
            placeholder="name@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            autoComplete="email"
            required
          />
        </label>

        <label style={{ display: "grid", gap: 6 }}>
          <span>Password</span>
          <input
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            autoComplete="current-password"
            required
          />
        </label>

        <button type="submit" disabled={submitting} style={{ padding: "10px 12px" }}>
          {submitting ? "Signing in…" : "Sign in"}
        </button>
      </form>
    </div>
  );
}
